import { Component, Element, h, Prop } from '@stencil/core';

@Component({
  tag: 'wdpr-progress-bar-continuous',
  shadow: true,
})
export class WdprProgressBarContinuous {
  @Element() el: HTMLWdprProgressBarContinuousElement;

  /**
   * When false, renders an indeterminate progress bar.
   * Indeterminate MUST NOT set aria-valuenow/min/max.
   */
  @Prop({ reflect: true }) determinate: boolean = true;
  @Prop({ reflect: true }) progress: number = 0;
  @Prop({ reflect: true }) max: number = 100;
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string;
  @Prop({ attribute: 'aria-labelledby' }) a11yLabelledBy?: string;

  private get _safeMax(): number {
    return Number.isFinite(this.max) && this.max > 0 ? this.max : 100;
  }

  private get _safeNow(): number {
    const now = Number.isFinite(this.progress) ? this.progress : 0;

    return Math.min(Math.max(now, 0), this._safeMax);
  }

  private get _ariaNameAttrs(): Record<string, string> {
    const labelledBy = this.a11yLabelledBy?.trim();
    if (labelledBy) return { 'aria-labelledby': labelledBy };

    const label = this.a11yLabel?.trim();
    if (label) return { 'aria-label': label };

    // Fallback to avoid an unnamed progressbar.
    return { 'aria-label': 'Progress' };
  }

  private get _ariaValueAttrs(): Record<string, string> {
    if (!this.determinate) return {};

    return {
      'aria-valuenow': String(this._safeNow),
      'aria-valuemin': '0',
      'aria-valuemax': String(this._safeMax),
    };
  }

  render() {
    return (
      <div class="flex flex-col gap-050 w-full" role="progressbar" {...this._ariaNameAttrs} {...this._ariaValueAttrs} part="root">
        <div class="w-full bg-surface-neutral-light rounded-pill h-075 overflow-hidden" part="track">
          <wdpr-progress-indicator progress={this._safeNow} max={this._safeMax} active={true}></wdpr-progress-indicator>
        </div>
      </div>
    );
  }
}
